module adder_8bit(
    input [7:0] a,
    input [7:0] b,
    input cin,
    output [7:0] sum,
    output cout
);

wire [7:0] sum_low, sum_high;
wire carry_low, carry_high;

// Lower 4-bit adder
assign {carry_low, sum_low[3:0]} = a[3:0] + b[3:0] + cin;

// Upper 4-bit adder with carry-in from lower adder
assign {carry_high, sum_high[3:0]} = a[7:4] + b[7:4] + carry_low;

// Combine the results of the two adders
assign sum[3:0] = sum_low[3:0];
assign sum[7:4] = sum_high[3:0];
assign cout = carry_high;

endmodule
